#!/usr/bin/env bash
# Build gnosis-chaos as a NAPI-compatible Node.js native module.
#
# Output: dist/gnosis_chaos.node  (copied from target/release/libgnosis_chaos.{dylib,so})
#
# Node loads .node files by dlopen; the NAPI registration symbols are published
# by napi-derive via the cdylib crate-type.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
cd "$SCRIPT_DIR"

OUT_DIR="$SCRIPT_DIR/dist"
mkdir -p "$OUT_DIR"

echo "[build-napi] cargo build --release --lib"
cargo build --release --lib

# Detect the output library per platform.
UNAME="$(uname -s)"
case "$UNAME" in
  Darwin)
    SRC="target/release/libgnosis_chaos.dylib"
    ;;
  Linux)
    SRC="target/release/libgnosis_chaos.so"
    ;;
  MINGW*|MSYS*|CYGWIN*)
    SRC="target/release/gnosis_chaos.dll"
    ;;
  *)
    echo "[build-napi] unsupported platform: $UNAME" >&2
    exit 1
    ;;
esac

if [[ ! -f "$SRC" ]]; then
  echo "[build-napi] expected artifact missing: $SRC" >&2
  exit 1
fi

DST="$OUT_DIR/gnosis_chaos.node"
cp "$SRC" "$DST"

SIZE="$(wc -c < "$DST" | tr -d ' ')"
echo "[build-napi] wrote $DST (${SIZE} bytes)"
